import{_ as o,o as t,c as r,a2 as a}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Character progression","description":"","frontmatter":{},"headers":[],"relativePath":"guide/character-progression.md","filePath":"guide/character-progression.md","lastUpdated":1781996549000}'),s={name:"guide/character-progression.md"};function d(i,e,c,n,l,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="character-progression" tabindex="-1">Character progression <a class="header-anchor" href="#character-progression" aria-label="Permalink to &quot;Character progression&quot;">​</a></h1><p>E4.5 adds the first additive RPG progression layer: character XP/level, core stats, and skills. The implementation is pure and reversible so future combat, health, and economy work can consume bonuses without this ticket rewiring damage or max-HP rules.</p><p>Source lives in <code>src/game/progression/</code> with a thin Redux wrapper in <code>src/store/progressionSlice.ts</code>.</p><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h2><p>The saveable <code>ProgressionState</code> contains:</p><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>level</code></td><td>Character level derived from lifetime character XP.</td></tr><tr><td><code>xp</code></td><td>Lifetime character XP.</td></tr><tr><td><code>nextLevelXp</code></td><td>XP threshold for the next character level.</td></tr><tr><td><code>stats</code></td><td>Core stat tracks: <code>strength</code>, <code>agility</code>, <code>endurance</code>. Stats start at level <code>10</code>.</td></tr><tr><td><code>skills</code></td><td>Skill tracks: <code>melee</code>, <code>trade</code>, <code>survival</code>. Skills start at level <code>1</code>.</td></tr></tbody></table><p>Progression is awarded by <code>ProgressionEvent</code>: a source label, character XP, and optional stat/skill XP deltas. <code>applyProgressionEvent</code> returns a fresh state and never mutates the input.</p><p>Current event helpers:</p><ul><li><code>combatKillProgressionEvent(&#39;soldier&#39; | &#39;caravan&#39;)</code> — used by the combat defeat edge in the forest scene.</li><li><code>purchaseProgressionEvent({ value })</code> — the economy purchase hook for E4.4+ buying code. It is available now even if a concrete shop UI is not wired yet.</li></ul><h2 id="store-integration" tabindex="-1">Store integration <a class="header-anchor" href="#store-integration" aria-label="Permalink to &quot;Store integration&quot;">​</a></h2><p><code>progressionSlice</code> exposes:</p><ul><li><code>recordCombatKill(target)</code> for combat/scene defeat callbacks.</li><li><code>recordPurchase({ value })</code> for buying systems.</li><li><code>awardProgression(event)</code> for explicit event tests/tools.</li><li><code>resetProgression()</code> for New Game.</li><li><code>restoreProgression(state)</code> for Continue.</li></ul><p>The live forest scene emits <code>onEnemyDefeated</code> when a soldier or caravan dies. <code>GameCanvas</code> dispatches <code>recordCombatKill</code> from that edge. Loot pickup remains separate: caravan loot still flows through <code>onCaravanLooted</code> → <code>caravanLootToPickups</code> → <code>pickUpLoot</code>.</p><h2 id="derived-bonuses" tabindex="-1">Derived bonuses <a class="header-anchor" href="#derived-bonuses" aria-label="Permalink to &quot;Derived bonuses&quot;">​</a></h2><p>Selectors expose bonuses for later consumption, but they are not applied to damage, max HP, or movement in E4.5:</p><ul><li><code>selectDamageMultiplier</code></li><li><code>selectMaxHealthBonus</code></li><li><code>selectMovementSpeedMultiplier</code></li></ul><p>That keeps this change additive. A later ticket can decide exactly where these bonuses enter combat, health, controller speed, and UI presentation.</p><h2 id="save-format" tabindex="-1">Save format <a class="header-anchor" href="#save-format" aria-label="Permalink to &quot;Save format&quot;">​</a></h2><p>Progression is persisted in save schema v4. Older saves migrate forward with a fresh baseline progression state. Current saves round-trip the full <code>ProgressionState</code>, so XP/stat/skill gains survive Continue.</p>',19)])])}const m=o(s,[["render",d]]);export{u as __pageData,m as default};
